module top_module(
    input [31:0] in_vector,
    output reg [5:0] out_count
);integer i;
    reg [5:0] obf_count;

    always @(*) begin
        obf_count = 0;
        for (i = 0; i < 32; i = i + 1) begin
            if (in_vector[i] == 1) begin
                obf_count = obf_count + 1;
            end
        end
        out_count = obf_count;
    end

endmodule
